## 任务三：在 `internal/service/devmachine/resource_builder_test.go` 中追加测试

在 `buildPodSpec` 的 `Describe` 块内追加 Context：

```go
Context("when VSCode with one RW storage", func() {
    It("should add shared-rw-volume to basic volumes", func() {
        request.WebIDE = devmachinemodel.WebIDEVSCode
        request.Storage = []devmachinemodel.Storage{
            {StoragePath: "user/data", MountPath: "/data", ReadOnly: false},
        }
        podSpec := buildPodSpec(request, "mock-image:latest")

        // 1 基础卷(dev-volume) + 1 shared-rw-volume = 2
        Expect(podSpec.Volumes).To(HaveLen(2))
        volumeNames := make([]string, len(podSpec.Volumes))
        for i, v := range podSpec.Volumes {
            volumeNames[i] = v.Name
        }
        Expect(volumeNames).To(ContainElement(SharedRWVolumeName))
    })
})

Context("when Jupyter with 2 RW and 1 RO storage entries", func() {
    It("should deduplicate to 2 shared volumes", func() {
        request.WebIDE = devmachinemodel.WebIDEJupyter
        request.Storage = []devmachinemodel.Storage{
            {StoragePath: "path/a", MountPath: "/a", ReadOnly: false},
            {StoragePath: "path/b", MountPath: "/b", ReadOnly: false},
            {StoragePath: "path/c", MountPath: "/c", ReadOnly: true},
        }
        podSpec := buildPodSpec(request, "mock-image:latest")

        // 2 基础卷(dev-volume + bootstrap-jupyter) + 2 shared = 4
        Expect(podSpec.Volumes).To(HaveLen(4))
    })
})
```

