    92→func Load(path string) (*Config, error) {
    93→	viper.SetConfigFile(path)
    94→	viper.SetConfigType("yaml")
    95→
    96→	// 设置默认值
    97→	viper.SetDefault("server.mode", "debug")
    98→	viper.SetDefault("log.level", "info")
    99→	viper.SetDefault("log.outputPath", "stdout")
   100→	viper.SetDefault("log.printRequestParams", false)
   101→	viper.SetDefault("log.skipFileOperations", true)
   102→	viper.SetDefault("auth.tokenTtl", 3600)
   103→	viper.SetDefault("auth.authType", "jwt")
   104→	viper.SetDefault("auth.authType", "jwt")
   105→	viper.SetDefault("k8s.namespace", "default")
   106→	viper.SetDefault("initContainer.image", "gz01-srdart.srdcloud.cn/tdp-paas/tdp_paas-tap-snapshot-docker-local/dev-bootstrap:v1.0.1-rc2")
   107→	viper.SetDefault("sharedStorage.rwPV.name", "shared-rw-pv")
   108→	viper.SetDefault("sharedStorage.rwPV.subPath", "")
   109→	viper.SetDefault("sharedStorage.roPV.name", "shared-ro-pv")
   110→	viper.SetDefault("sharedStorage.roPV.subPath", "")
   111→
   112→	// 允许从环境变量读取
   113→	viper.AutomaticEnv()
   114→
   115→	if err := viper.ReadInConfig(); err != nil {
   116→		if _, ok := err.(viper.ConfigFileNotFoundError); !ok {
   117→			return nil, fmt.Errorf("error reading config file: %w", err)
   118→		}
   119→		// 配置文件不存在时使用默认值
   120→	}
   121→
   122→	var cfg Config
   123→	if err := viper.Unmarshal(&cfg); err != nil {
   124→		return nil, fmt.Errorf("error unmarshaling config: %w", err)
   125→	}
   126→
   127→	// 设置认证开关的默认值（如果配置文件中没有设置）
   128→	if !viper.IsSet("auth.enabled") {
   129→		if cfg.Server.Mode == "debug" {
   130→			cfg.Auth.Enabled = false
   131→		} else {
   132→			cfg.Auth.Enabled = true
   133→		}
   134→	}
   135→
   136→	// 从环境变量覆盖敏感信息
   137→	if jwtSecret := os.Getenv("JWT_SECRET"); jwtSecret != "" {
   138→		cfg.Auth.JWTSecret = jwtSecret
   139→	}
   140→	if s3Key := os.Getenv("S3_ACCESS_KEY"); s3Key != "" {
   141→		cfg.S3.AccessKey = s3Key
   142→	}
   143→	if s3Secret := os.Getenv("S3_SECRET_KEY"); s3Secret != "" {
   144→		cfg.S3.SecretKey = s3Secret
   145→	}
   146→	if harborPass := os.Getenv("HARBOR_PASSWORD"); harborPass != "" {
   147→		cfg.Harbor.Password = harborPass
   148→	}
   149→	if authEnabled := os.Getenv("AUTH_ENABLED"); authEnabled != "" {
   150→		if authEnabled == "true" {
   151→			cfg.Auth.Enabled = true
   152→		} else if authEnabled == "false" {
   153→			cfg.Auth.Enabled = false
   154→		}
   155→	}
   156→
   157→	// 验证认证类型
   158→	if cfg.Auth.Enabled && cfg.Auth.AuthType != "jwt" && cfg.Auth.AuthType != "basic_auth" {
   159→		return nil, fmt.Errorf("invalid auth_type: %s, must be 'jwt' or 'basic_auth'", cfg.Auth.AuthType)
   160→	}
   161→
   162→	return &cfg, nil
   163→}
