    99→func (s *service) CreateDevmachine(ctx context.Context, request *devmachinemodel.CreateDevmachineRequest) (*devmachinemodel.CreateDevmachineResponse, error) {
   100→	// 验证请求参数
   101→	if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
   102→		return nil, NewValidationError("devmachine", request.Name, err)
   103→	}
   104→
   105→	var err error
   106→
   107→	defer func() {
   108→		if err != nil {
   109→			log.Printf("error: failed to create devmachine, try to cleanup: %v", err)
   110→			_, _ = s.DeleteDevmachine(ctx, request.Namespace, request.Name)
   111→		}
   112→	}()
   113→
   114→	// 1. 兼容兜底：确保 namespace 下共享 PVC 存在（历史 namespace 补建）
   115→	// TODO: 新环境稳定后可移除此兼容逻辑
   116→	if len(request.Storage) > 0 {
   117→		if err = s.ensureSharedPVCs(ctx, request.Namespace, request.Storage); err != nil {
   118→			return nil, err
   119→		}
   120→	}
   121→
   122→	// 3. 创建 Deployment
   123→	deployment := generateDevMachineDeployment(request, s.config.InitContainer.Image)
   124→	if err := s.k8sClient.CreateDeployment(ctx, deployment); err != nil {
   125→		return nil, NewResourceError("Deployment", request.Name, "create", err)
   126→	}
   127→
   128→	// 3. 创建 Service
   129→	service := generateDevMachineService(request)
   130→	if err := s.k8sClient.CreateService(ctx, service); err != nil {
   131→		return nil, NewResourceError("Service", request.Name+serviceSuffix, "create", err)
   132→	}
   133→
   134→	// 4. 创建 Ingress
   135→	ingress := generateDevMachineIngress(request)
   136→	if err := s.k8sClient.CreateIngress(ctx, ingress); err != nil {
   137→		return nil, NewResourceError("Ingress", request.Name+ingressSuffix, "create", err)
   138→	}
   139→
   140→	return &devmachinemodel.CreateDevmachineResponse{
   141→		Name:   request.Name,
   142→		Status: "pending",
   143→		WebUrl: fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(request.Namespace, request.Name)),
   144→	}, nil
   145→}
