   147→func (s *service) UpdateDevmachine(ctx context.Context, request *devmachinemodel.UpdateDevmachineRequest) (*devmachinemodel.UpdateDevmachineResponse, error) {
   148→	// 验证请求参数
   149→	if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
   150→		return nil, NewValidationError("devmachine", request.Name, err)
   151→	}
   152→
   153→	// 1. 获取现有 Deployment
   154→	deployment, err := s.k8sClient.GetDeployment(ctx, request.Namespace, request.Name)
   155→	if err != nil {
   156→		return nil, NewResourceError("Deployment", request.Name, "get", err)
   157→	}
   158→
   159→	// 2. 更新 Deployment 配置
   160→	deployment.Spec.Template.Spec.Containers[0].Image = request.ImageName
   161→
   162→	// 更新资源请求
   163→	if request.CPU != "" || request.Memory != "" || request.GPU != "" {
   164→		// 构建新的资源请求
   165→		resources := BuildResourceRequirements(request.CPU, request.Memory, request.GPU, request.GPUName)
   166→		deployment.Spec.Template.Spec.Containers[0].Resources = resources
   167→	}
   168→
   169→	// 更新节点选择器
   170→	if len(request.NodeSelector) > 0 {
   171→		deployment.Spec.Template.Spec.NodeSelector = request.NodeSelector
   172→	}
   173→
   174→	// 更新标签
   175→	if len(request.Labels) > 0 {
   176→		for k, v := range request.Labels {
   177→			deployment.Labels[k] = v
   178→			deployment.Spec.Template.Labels[k] = v
   179→		}
   180→	}
   181→
   182→	// 更新注解
   183→	if len(request.Annotations) > 0 {
   184→		for k, v := range request.Annotations {
   185→			deployment.Annotations[k] = v
   186→			deployment.Spec.Template.Annotations[k] = v
   187→		}
   188→	}
   189→
   190→	// 更新队列名称
   191→	if request.QueueName != "" {
   192→		deployment.Spec.Template.Annotations[volcanoQueueName] = request.QueueName
   193→	}
   194→
   195→	// 3. 更新 Deployment
   196→	if err := s.k8sClient.UpdateDeployment(ctx, deployment); err != nil {
   197→		return nil, NewResourceError("Deployment", request.Name, "update", err)
