package devmachine

import (
	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"
	corev1 "k8s.io/api/core/v1"

	devmachinemodel "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/model/devmachine"
)

var _ = Describe("Storage Builder", func() {
	Describe("buildSharedPVC", func() {
		Context("when readOnly is false", func() {
			It("should create ReadWriteMany PVC explicitly bound to the given PV", func() {
				pvc := buildSharedPVC("test-ns", "shared-rw-pvc", "shared-rw-pv", false)

				Expect(pvc.Name).To(Equal("shared-rw-pvc"))
				Expect(pvc.Namespace).To(Equal("test-ns"))
				Expect(pvc.Spec.VolumeName).To(Equal("shared-rw-pv"))
				Expect(pvc.Spec.AccessModes).To(Equal([]corev1.PersistentVolumeAccessMode{corev1.ReadWriteMany}))
				Expect(pvc.Spec.StorageClassName).NotTo(BeNil())
				Expect(*pvc.Spec.StorageClassName).To(Equal(""))
			})
		})

		Context("when readOnly is true", func() {
			It("should create ReadOnlyMany PVC", func() {
				pvc := buildSharedPVC("test-ns", "shared-ro-pvc", "shared-ro-pv", true)

				Expect(pvc.Spec.AccessModes).To(Equal([]corev1.PersistentVolumeAccessMode{corev1.ReadOnlyMany}))
				Expect(pvc.Spec.VolumeName).To(Equal("shared-ro-pv"))
			})
		})
	})

	Describe("buildSharedVolumes", func() {
		Context("when storage list is empty", func() {
			It("should return nil", func() {
				volumes := buildSharedVolumes(nil)
				Expect(volumes).To(BeNil())
			})
		})

		Context("when all storages are read-write", func() {
			It("should return 1 volume named shared-rw-volume referencing shared-rw-pvc", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/data", ReadOnly: false},
					{StoragePath: "user/code", MountPath: "/code", ReadOnly: false},
				}
				volumes := buildSharedVolumes(storages)

				Expect(volumes).To(HaveLen(1))
				Expect(volumes[0].Name).To(Equal(SharedRWVolumeName))
				Expect(volumes[0].PersistentVolumeClaim).NotTo(BeNil())
				Expect(volumes[0].PersistentVolumeClaim.ClaimName).To(Equal(SharedRWPVCName))
			})
		})

		Context("when all storages are read-only", func() {
			It("should return 1 volume named shared-ro-volume referencing shared-ro-pvc with ReadOnly=true", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "shared/models", MountPath: "/models", ReadOnly: true},
				}
				volumes := buildSharedVolumes(storages)

				Expect(volumes).To(HaveLen(1))
				Expect(volumes[0].Name).To(Equal(SharedROVolumeName))
				Expect(volumes[0].PersistentVolumeClaim).NotTo(BeNil())
				Expect(volumes[0].PersistentVolumeClaim.ClaimName).To(Equal(SharedROPVCName))
				Expect(volumes[0].PersistentVolumeClaim.ReadOnly).To(BeTrue())
			})
		})

		Context("when storages include both RW and RO", func() {
			It("should return exactly 2 volumes without duplicates", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "path/a", MountPath: "/a", ReadOnly: false},
					{StoragePath: "path/b", MountPath: "/b", ReadOnly: false},
					{StoragePath: "path/c", MountPath: "/c", ReadOnly: true},
				}
				volumes := buildSharedVolumes(storages)

				Expect(volumes).To(HaveLen(2))
				volumeNames := make([]string, len(volumes))
				for i, v := range volumes {
					volumeNames[i] = v.Name
				}
				Expect(volumeNames).To(ContainElement(SharedRWVolumeName))
				Expect(volumeNames).To(ContainElement(SharedROVolumeName))
			})
		})
	})

	Describe("buildSharedVolumeMounts", func() {
		Context("when storage list is empty", func() {
			It("should return nil", func() {
				mounts := buildSharedVolumeMounts(nil)
				Expect(mounts).To(BeNil())
			})
		})

		Context("when storages have RW and RO entries", func() {
			It("should map StoragePath to SubPath and MountPath correctly", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "user/data", MountPath: "/workspace/data", ReadOnly: false},
					{StoragePath: "shared/models", MountPath: "/models", ReadOnly: true},
				}
				mounts := buildSharedVolumeMounts(storages)

				Expect(mounts).To(HaveLen(2))
				Expect(mounts[0].Name).To(Equal(SharedRWVolumeName))
				Expect(mounts[0].SubPath).To(Equal("user/data"))
				Expect(mounts[0].MountPath).To(Equal("/workspace/data"))
				Expect(mounts[0].ReadOnly).To(BeFalse())

				Expect(mounts[1].Name).To(Equal(SharedROVolumeName))
				Expect(mounts[1].SubPath).To(Equal("shared/models"))
				Expect(mounts[1].MountPath).To(Equal("/models"))
				Expect(mounts[1].ReadOnly).To(BeTrue())
			})
		})

		Context("when multiple storages share the same RW volume", func() {
			It("should create separate mounts each with their own subPath", func() {
				storages := []devmachinemodel.Storage{
					{StoragePath: "project/a", MountPath: "/data/a", ReadOnly: false},
					{StoragePath: "project/b", MountPath: "/data/b", ReadOnly: false},
				}
				mounts := buildSharedVolumeMounts(storages)

				Expect(mounts).To(HaveLen(2))
				Expect(mounts[0].Name).To(Equal(SharedRWVolumeName))
				Expect(mounts[0].SubPath).To(Equal("project/a"))
				Expect(mounts[1].Name).To(Equal(SharedRWVolumeName))
				Expect(mounts[1].SubPath).To(Equal("project/b"))
			})
		})
	})

	Describe("buildSharedPV", func() {
		Context("when csiConfig is nil", func() {
			BeforeEach(func() {
				SetCSIConfig(nil)
			})

			It("should return an error without panicking", func() {
				pv, err := buildSharedPV("shared-rw-pv", "", false)

				Expect(err).To(HaveOccurred())
				Expect(err.Error()).To(ContainSubstring("CSI config not initialized"))
				Expect(pv).To(BeNil())
			})
		})

		Context("when csiConfig is initialized", func() {
			BeforeEach(func() {
				SetCSIConfig(&CSIConfig{
					Driver:          "csi.juicefs.com",
					SecretName:      "juicefs-secret",
					SecretNamespace: "kube-system",
				})
			})

			AfterEach(func() {
				SetCSIConfig(nil)
			})

			It("should create ReadWriteMany PV with Retain reclaim policy", func() {
				pv, err := buildSharedPV("shared-rw-pv", "", false)

				Expect(err).NotTo(HaveOccurred())
				Expect(pv).NotTo(BeNil())
				Expect(pv.Spec.AccessModes).To(Equal([]corev1.PersistentVolumeAccessMode{corev1.ReadWriteMany}))
				Expect(pv.Spec.PersistentVolumeReclaimPolicy).To(Equal(corev1.PersistentVolumeReclaimRetain))
			})

			It("should create ReadOnlyMany PV when readOnly is true", func() {
				pv, err := buildSharedPV("shared-ro-pv", "", true)

				Expect(err).NotTo(HaveOccurred())
				Expect(pv.Spec.AccessModes).To(Equal([]corev1.PersistentVolumeAccessMode{corev1.ReadOnlyMany}))
			})

			It("should set subPath in VolumeAttributes when subPath is not empty", func() {
				pv, err := buildSharedPV("shared-rw-pv", "my/path", false)

				Expect(err).NotTo(HaveOccurred())
				Expect(pv.Spec.CSI).NotTo(BeNil())
				Expect(pv.Spec.CSI.VolumeAttributes["subPath"]).To(Equal("my/path"))
			})

			It("should not set subPath in VolumeAttributes when subPath is empty", func() {
				pv, err := buildSharedPV("shared-rw-pv", "", false)

				Expect(err).NotTo(HaveOccurred())
				Expect(pv.Spec.CSI).NotTo(BeNil())
				_, exists := pv.Spec.CSI.VolumeAttributes["subPath"]
				Expect(exists).To(BeFalse())
			})
		})
	})
})
